import { FormEvent, useMemo, useState } from 'react';
import axios from 'axios';
import {
  Avatar,
  Box,
  Button,
  CircularProgress,
  Fab,
  IconButton,
  Paper,
  Stack,
  TextField,
  Typography,
} from '@mui/material';
import SmartToyRoundedIcon from '@mui/icons-material/SmartToyRounded';
import CloseRoundedIcon from '@mui/icons-material/CloseRounded';
import SendRoundedIcon from '@mui/icons-material/SendRounded';
import AddCircleRoundedIcon from '@mui/icons-material/AddCircleRounded';
import LinkRoundedIcon from '@mui/icons-material/LinkRounded';
import PersonRoundedIcon from '@mui/icons-material/PersonRounded';
import { AI_API_URL } from '../constants';
import { RecipeFormData } from '../types';
import { glassPanelSx } from '../utils/glassPanel';

interface AssistantRecipe {
  name: string;
  cuisine: string;
  ingredients: string;
  steps: string;
  cookingTime: number;
  photoUrl: string | null;
  sourceUrl: string | null;
  sourceName: string;
}

interface RecipeAssistantProps {
  authHeaders?: { Authorization: string };
  onAddRecipe: (recipe: RecipeFormData) => Promise<void>;
}

interface ChatMessage {
  id: string;
  role: 'user' | 'assistant';
  text: string;
  recipe?: AssistantRecipe;
  error?: boolean;
}

export default function RecipeAssistant({ authHeaders, onAddRecipe }: RecipeAssistantProps) {
  const [open, setOpen] = useState(false);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [addingId, setAddingId] = useState<string | null>(null);
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: 'welcome',
      role: 'assistant',
      text: 'Hi! Ask any recipe name like "paneer butter masala" and I will fetch ingredients, time, steps, and image for you.',
    },
  ]);

  const canSend = useMemo(() => input.trim().length > 0 && !loading, [input, loading]);

  const handleSend = async (event: FormEvent) => {
    event.preventDefault();
    if (!canSend || !authHeaders) return;

    const query = input.trim();
    const userMessage: ChatMessage = {
      id: `u-${Date.now()}`,
      role: 'user',
      text: query,
    };
    setMessages((prev) => [...prev, userMessage]);
    setInput('');
    setLoading(true);

    try {
      const response = await axios.get<{ recipe: AssistantRecipe }>(`${AI_API_URL}/recipe-search`, {
        params: { query },
        headers: authHeaders,
      });

      const recipe = response.data.recipe;
      const assistantMessage: ChatMessage = {
        id: `a-${Date.now()}`,
        role: 'assistant',
        text: `Found recipe for ${recipe.name}. You can add it directly to your recipes.`,
        recipe,
      };
      setMessages((prev) => [...prev, assistantMessage]);
    } catch (error) {
      const message = axios.isAxiosError(error)
        ? error.response?.data?.message || 'Could not fetch a recipe now. Try another recipe name.'
        : 'Could not fetch a recipe now. Try another recipe name.';
      setMessages((prev) => [
        ...prev,
        {
          id: `e-${Date.now()}`,
          role: 'assistant',
          text: message,
          error: true,
        },
      ]);
    } finally {
      setLoading(false);
    }
  };

  const handleAddRecipe = async (messageId: string, recipe: AssistantRecipe) => {
    setAddingId(messageId);
    try {
      await onAddRecipe({
        name: recipe.name,
        cuisine: recipe.cuisine || 'Other',
        ingredients: recipe.ingredients,
        steps: recipe.steps,
        cookingTime: recipe.cookingTime || 30,
        photoUrl: recipe.photoUrl,
        isFavorite: false,
      });
      setMessages((prev) =>
        prev.map((message) =>
          message.id === messageId
            ? { ...message, text: `${message.text} Added to your recipes.` }
            : message
        )
      );
    } finally {
      setAddingId(null);
    }
  };

  return (
    <>
      {open ? (
        <Paper
          elevation={0}
          sx={{
            position: 'fixed',
            right: { xs: 12, sm: 20 },
            bottom: { xs: 12, sm: 20 },
            width: { xs: 'calc(100vw - 24px)', sm: 390 },
            height: { xs: '72vh', sm: 560 },
            zIndex: 1300,
            borderRadius: 3,
            display: 'flex',
            flexDirection: 'column',
            overflow: 'hidden',
            ...glassPanelSx(),
          }}
        >
          <Box
            sx={{
              p: 1.4,
              borderBottom: (theme) =>
                theme.palette.mode === 'dark'
                  ? '1px solid rgba(166, 210, 245, 0.25)'
                  : '1px solid rgba(40, 111, 163, 0.2)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'space-between',
            }}
          >
            <Stack direction="row" spacing={1} alignItems="center">
              <Avatar sx={{ width: 30, height: 30, bgcolor: 'primary.main' }}>
                <SmartToyRoundedIcon fontSize="small" />
              </Avatar>
              <Typography variant="subtitle1" fontWeight={700}>
                Recipe AI
              </Typography>
            </Stack>
            <IconButton onClick={() => setOpen(false)} size="small">
              <CloseRoundedIcon />
            </IconButton>
          </Box>

          <Box sx={{ flex: 1, overflowY: 'auto', p: 1.5 }}>
            <Stack spacing={1.2}>
              {messages.map((message) => (
                <Box
                  key={message.id}
                  sx={{
                    alignSelf: message.role === 'user' ? 'flex-end' : 'flex-start',
                    maxWidth: '92%',
                  }}
                >
                  <Stack direction="row" spacing={0.8} alignItems="flex-start">
                    {message.role === 'assistant' ? (
                      <SmartToyRoundedIcon color={message.error ? 'error' : 'primary'} fontSize="small" />
                    ) : (
                      <PersonRoundedIcon color="action" fontSize="small" />
                    )}
                    <Paper
                      elevation={0}
                      sx={{
                        px: 1.2,
                        py: 1,
                        borderRadius: 2,
                        ...(message.role === 'user'
                          ? {
                              backgroundColor: 'primary.main',
                              color: 'primary.contrastText',
                            }
                          : glassPanelSx()),
                      }}
                    >
                      <Typography variant="body2">{message.text}</Typography>
                    </Paper>
                  </Stack>

                  {message.recipe ? (
                    <Paper elevation={0} sx={{ mt: 0.8, p: 1.2, borderRadius: 2, ...glassPanelSx() }}>
                      {message.recipe.photoUrl ? (
                        <Box
                          component="img"
                          src={message.recipe.photoUrl}
                          alt={message.recipe.name}
                          sx={{ width: '100%', height: 140, objectFit: 'cover', borderRadius: 1.5, mb: 1 }}
                        />
                      ) : null}
                      <Typography variant="subtitle2" fontWeight={700}>
                        {message.recipe.name}
                      </Typography>
                      <Typography variant="caption" color="text.secondary" display="block" sx={{ mb: 0.5 }}>
                        {message.recipe.cuisine} • {message.recipe.cookingTime} min
                      </Typography>
                      <Typography variant="body2" sx={{ mb: 0.6 }}>
                        <strong>Ingredients:</strong> {message.recipe.ingredients}
                      </Typography>
                      <Typography variant="body2" sx={{ mb: 1 }}>
                        <strong>Steps:</strong> {message.recipe.steps}
                      </Typography>
                      <Stack direction="row" spacing={1} flexWrap="wrap">
                        <Button
                          size="small"
                          variant="contained"
                          startIcon={<AddCircleRoundedIcon />}
                          onClick={() => void handleAddRecipe(message.id, message.recipe!)}
                          disabled={addingId === message.id}
                        >
                          {addingId === message.id ? 'Adding...' : 'Add To Recipes'}
                        </Button>
                        {message.recipe.sourceUrl ? (
                          <Button
                            size="small"
                            variant="outlined"
                            startIcon={<LinkRoundedIcon />}
                            component="a"
                            href={message.recipe.sourceUrl}
                            target="_blank"
                            rel="noreferrer"
                          >
                            Source
                          </Button>
                        ) : null}
                      </Stack>
                    </Paper>
                  ) : null}
                </Box>
              ))}
              {loading ? (
                <Stack direction="row" spacing={1} alignItems="center" sx={{ pl: 0.5 }}>
                  <CircularProgress size={16} />
                  <Typography variant="caption" color="text.secondary">
                    Fetching recipe details...
                  </Typography>
                </Stack>
              ) : null}
            </Stack>
          </Box>

          <Box component="form" onSubmit={handleSend} sx={{ p: 1.2, borderTop: '1px solid', borderColor: 'divider' }}>
            <Stack direction="row" spacing={1}>
              <TextField
                size="small"
                fullWidth
                placeholder="Ask recipe name..."
                value={input}
                onChange={(event) => setInput(event.target.value)}
              />
              <IconButton type="submit" color="primary" disabled={!canSend}>
                <SendRoundedIcon />
              </IconButton>
            </Stack>
          </Box>
        </Paper>
      ) : null}

      <Fab
        color="primary"
        onClick={() => setOpen((prev) => !prev)}
        sx={{
          position: 'fixed',
          right: { xs: 14, sm: 22 },
          bottom: { xs: 14, sm: 22 },
          zIndex: 1299,
        }}
      >
        <SmartToyRoundedIcon />
      </Fab>
    </>
  );
}
